"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete, triggerShake } from "@/lib/learningMessages";

type MotionType = "symmetry" | "translation" | "rotation";

interface SceneItem {
  id: string;
  icon: string;
  name: string;
  type: MotionType;
  x: number; // 百分比位置
  y: number;
}

interface Scene {
  id: string;
  name: string;
  bg: string;
  items: SceneItem[];
}

const SCENES: Scene[] = [
  {
    id: "park",
    name: "公园里",
    bg: "linear-gradient(to bottom, #7DD3FC 0%, #7DD3FC 50%, #86EFAC 50%, #86EFAC 100%)",
    items: [
      { id: "p1", icon: "🎡", name: "摩天轮", type: "rotation", x: 15, y: 25 },
      { id: "p2", icon: "🛝", name: "滑滑梯", type: "translation", x: 75, y: 45 },
      { id: "p3", icon: "🦋", name: "蝴蝶", type: "symmetry", x: 50, y: 20 },
      { id: "p4", icon: "🚶", name: "走路的人", type: "translation", x: 35, y: 65 },
      { id: "p5", icon: "🪁", name: "风筝", type: "translation", x: 85, y: 15 },
      { id: "p6", icon: "🌸", name: "花朵", type: "symmetry", x: 60, y: 70 },
    ],
  },
  {
    id: "home",
    name: "家里",
    bg: "linear-gradient(to bottom, #FDE68A 0%, #FDE68A 60%, #D4A574 60%, #D4A574 100%)",
    items: [
      { id: "h1", icon: "🌀", name: "电风扇", type: "rotation", x: 20, y: 20 },
      { id: "h2", icon: "⏰", name: "时钟", type: "rotation", x: 70, y: 25 },
      { id: "h3", icon: "🛗", name: "电梯", type: "translation", x: 50, y: 45 },
      { id: "h4", icon: "🎭", name: "面具", type: "symmetry", x: 85, y: 35 },
      { id: "h5", icon: "📺", name: "电视", type: "symmetry", x: 15, y: 55 },
      { id: "h6", icon: "🚪", name: "开门", type: "rotation", x: 40, y: 65 },
    ],
  },
  {
    id: "school",
    name: "学校里",
    bg: "linear-gradient(to bottom, #C4B5FD 0%, #C4B5FD 50%, #F0FDF4 50%, #F0FDF4 100%)",
    items: [
      { id: "s1", icon: "✂️", name: "剪纸", type: "symmetry", x: 25, y: 35 },
      { id: "s2", icon: "🚇", name: "校车", type: "translation", x: 70, y: 70 },
      { id: "s3", icon: "📐", name: "三角板", type: "symmetry", x: 45, y: 40 },
      { id: "s4", icon: "🎠", name: "旋转木马", type: "rotation", x: 80, y: 30 },
      { id: "s5", icon: "📚", name: "课本", type: "symmetry", x: 15, y: 60 },
      { id: "s6", icon: "🏃", name: "跑步", type: "translation", x: 55, y: 70 },
    ],
  },
];

const TYPE_LABELS: Record<MotionType, { icon: string; label: string; color: string }> = {
  symmetry: { icon: "📄", label: "轴对称", color: "var(--primary)" },
  translation: { icon: "🚗", label: "平移", color: "var(--accent2)" },
  rotation: { icon: "🎡", label: "旋转", color: "var(--accent)" },
};

export default function ApplyPage() {
  const [sceneIndex, setSceneIndex] = useState(0);
  const [foundItems, setFoundItems] = useState<Set<string>>(new Set());
  const [currentType, setCurrentType] = useState<MotionType>("symmetry");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);
  const [showResult, setShowResult] = useState(false);

  const scene = SCENES[sceneIndex];
  const targetItems = scene.items.filter((i) => i.type === currentType);
  const foundCount = scene.items.filter(
    (i) => i.type === currentType && foundItems.has(i.id)
  ).length;
  const allFoundInType = foundCount === targetItems.length;

  const handleItemClick = (item: SceneItem) => {
    if (foundItems.has(item.id)) return;

    if (item.type === currentType) {
      setFoundItems((prev) => new Set([...prev, item.id]));
    } else {
      const el = document.getElementById("scene-area");
      triggerShake(el);
    }
  };

  const nextType = () => {
    if (currentType === "symmetry") {
      setCurrentType("translation");
    } else if (currentType === "translation") {
      setCurrentType("rotation");
    } else {
      // 完成这个场景
      if (sceneIndex < SCENES.length - 1) {
        setSceneIndex(sceneIndex + 1);
        setCurrentType("symmetry");
        setFoundItems(new Set());
      } else {
        setShowResult(true);
      }
    }
  };

  const totalFound = foundItems.size;
  const totalItems = SCENES.reduce((sum, s) => sum + s.items.length, 0);

  return (
    <StepShell topicId="motion" stepId="apply">
      <div className="space-y-5">
        {!showResult ? (
          <>
            {/* 场景信息 */}
            <div className="text-center">
              <h2 className="text-xl font-bold text-[var(--text)]">
                找一找：{scene.name}的{TYPE_LABELS[currentType].label}
              </h2>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                第 {sceneIndex + 1} / {SCENES.length} 个场景 · 第{" "}
                {currentType === "symmetry" ? 1 : currentType === "translation" ? 2 : 3} 种
              </p>
            </div>

            {/* 当前任务类型 */}
            <div className="flex justify-center">
              <div
                className="flex items-center gap-2 rounded-full px-4 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)]"
                style={{ backgroundColor: TYPE_LABELS[currentType].color }}
              >
                <span>{TYPE_LABELS[currentType].icon}</span>
                <span>
                  找出所有{TYPE_LABELS[currentType].label}
                  （{foundCount}/{targetItems.length}）
                </span>
              </div>
            </div>

            {/* 场景区域 */}
            <div
              id="scene-area"
              className="relative mx-auto w-full max-w-md overflow-hidden rounded-[var(--radius)] border-2 border-[var(--border)] shadow-[var(--shadow-md)]"
              style={{ height: 320, background: scene.bg }}
            >
              {/* 场景装饰 */}
              <div className="absolute top-4 right-4 text-3xl">☀️</div>
              <div className="absolute top-6 left-8 text-2xl opacity-80">☁️</div>
              <div className="absolute top-10 left-20 text-xl opacity-60">☁️</div>

              {/* 可点击的物品 */}
              {scene.items.map((item) => {
                const found = foundItems.has(item.id);
                const isTarget = item.type === currentType;
                return (
                  <button
                    key={item.id}
                    onClick={() => handleItemClick(item)}
                    className={`absolute -translate-x-1/2 -translate-y-1/2 transition-all ${
                      found
                        ? "scale-125"
                        : "hover:scale-110 active:scale-95"
                    }`}
                    style={{
                      left: `${item.x}%`,
                      top: `${item.y}%`,
                      fontSize: "2rem",
                    }}
                    title={item.name}
                  >
                    <span className={found ? "drop-shadow-lg" : ""}>{item.icon}</span>
                    {found && isTarget && (
                      <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-[var(--signal-success)] text-xs text-white shadow-md">
                        ✓
                      </span>
                    )}
                  </button>
                );
              })}
            </div>

            {/* 类型切换提示 */}
            <div className="flex justify-center gap-2">
              {(Object.keys(TYPE_LABELS) as MotionType[]).map((type) => {
                const done =
                  type === currentType
                    ? allFoundInType
                    : (currentType === "symmetry" && type !== "symmetry")
                      ? false
                      : (currentType === "translation" && type === "rotation")
                        ? false
                        : (currentType === "rotation" && type === "symmetry")
                          ? true
                          : (currentType === "rotation" && type === "translation")
                            ? true
                            : false;
                const isCurrent = type === currentType;
                return (
                  <div
                    key={type}
                    className={`flex items-center gap-1 rounded-full px-3 py-1 text-xs transition-all ${
                      isCurrent
                        ? "bg-[var(--bg-card)] font-bold text-[var(--text)] shadow-sm"
                        : done
                          ? "bg-[var(--signal-success)]/20 text-[var(--signal-success)]"
                          : "bg-[var(--bg-soft)] text-[var(--text-muted)]"
                    }`}
                  >
                    <span>{TYPE_LABELS[type].icon}</span>
                    <span>{TYPE_LABELS[type].label}</span>
                    {done && <span>✓</span>}
                  </div>
                );
              })}
            </div>

            {/* 下一步按钮 */}
            {allFoundInType && (
              <div className="flex justify-center">
                <button
                  onClick={nextType}
                  className="animate-float-in rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
                >
                  {currentType === "rotation"
                    ? sceneIndex < SCENES.length - 1
                      ? "下一个场景 →"
                      : "完成探索 →"
                    : `找下一种：${
                        TYPE_LABELS[
                          currentType === "symmetry" ? "translation" : "rotation"
                        ].label
                      } →`}
                </button>
              </div>
            )}
          </>
        ) : (
          /* 结果页面 */
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-5xl animate-bounce-soft">🏠</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-[var(--text-secondary)]">
              你在 {SCENES.length} 个场景里找到了 {totalFound} 种运动现象！
              <br />
              原来生活中到处都有轴对称、平移和旋转~
            </p>

            {/* 统计 */}
            <div className="mt-6 grid grid-cols-3 gap-3">
              {(Object.keys(TYPE_LABELS) as MotionType[]).map((type) => {
                const count = SCENES.reduce(
                  (sum, s) => sum + s.items.filter((i) => i.type === type).length,
                  0
                );
                return (
                  <div
                    key={type}
                    className="rounded-xl p-3"
                    style={{ backgroundColor: TYPE_LABELS[type].color + "20" }}
                  >
                    <div className="text-2xl">{TYPE_LABELS[type].icon}</div>
                    <p className="mt-1 text-xs text-[var(--text-secondary)]">
                      {TYPE_LABELS[type].label}
                    </p>
                    <p className="text-lg font-bold text-[var(--text)]">{count}</p>
                  </div>
                );
              })}
            </div>

            <div className="mt-6 flex flex-wrap justify-center gap-3">
              <button
                onClick={() => {
                  setSceneIndex(0);
                  setFoundItems(new Set());
                  setCurrentType("symmetry");
                  setShowResult(false);
                }}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                再玩一次
              </button>
              <Link
                href="/learn/motion/discover"
                className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
              >
                下一步：说一说 →
              </Link>
            </div>
          </section>
        )}
      </div>
    </StepShell>
  );
}
